//! Jolt's RISC-V instruction kinds, metadata, and tracer-free cycle views.
//!
//! Each unit struct in [`instructions`] represents one instruction kind (real
//! RV64I/M opcode or virtual sequence helper). [`Flags`] exposes its static
//! R1CS circuit flags ([`CircuitFlagSet`]) and witness-generation flags
//! ([`InstructionFlagSet`]); per-instruction impls are generated by the
//! `Flags` derive macro in `jolt-riscv-derive`.

#[cfg(feature = "field-inline")]
pub mod field_inline;
mod flags;
pub mod instructions;
mod kind;
mod profile;
mod row;
mod row_data;
pub mod trace;
pub mod trace_row;
mod uncompress;

