/// Declares a Jolt RISC-V instruction kind and (optionally) its `Flags` impl.
///
/// Two forms:
///
/// ```ignore
/// // With circuit + instruction flag config — emits a `Flags` impl:
/// jolt_instruction!(
///     /// RV64I ADD: `rd = rs1 + rs2` (wrapping).
///     Add,
///     circuit flags: [AddOperands, WriteLookupOutputToRD],
///     instruction flags: [LeftOperandIsRs1Value, RightOperandIsRs2Value]
/// );
///
/// // No flag config — struct only, no `Flags` impl:
/// jolt_instruction!(
///     /// Zicsr CSRRS: atomic CSR read+set bits.
///     Csrrs
/// );
/// ```
#[macro_export]
macro_rules! jolt_instruction {
    (
        $(#[$attr:meta])*
        $name:ident,
        circuit flags: [$($circuit:ident),* $(,)?],
        instruction flags: [$($instruction:ident),* $(,)?] $(,)?
    ) => {
        $crate::jolt_instruction!(@struct $(#[$attr])* $name);

        impl<T: $crate::JoltInstructionRowData> $crate::Flags for $name<T> {
            #[inline]
            fn circuit_flags(&self) -> $crate::CircuitFlagSet {
                let instruction: $crate::JoltInstructionRow = self.0.into();
                let mut flags = $crate::CircuitFlagSet::default()
                    $(.set($crate::CircuitFlags::$circuit))*;
                if let Some(virtual_sequence_remaining) = instruction.virtual_sequence_remaining {
                    flags = flags.set($crate::CircuitFlags::VirtualInstruction);
                    if virtual_sequence_remaining == 0 {
                        flags = flags.set($crate::CircuitFlags::IsLastInSequence);
                    }
                }
                if instruction.virtual_sequence_remaining.unwrap_or(0) != 0 {
                    flags = flags.set($crate::CircuitFlags::DoNotUpdateUnexpandedPC);
                }
                if instruction.is_compressed {
                    flags = flags.set($crate::CircuitFlags::IsCompressed);
                }
                if instruction.is_first_in_sequence {
                    flags = flags.set($crate::CircuitFlags::IsFirstInSequence);
                }
                flags
            }

            #[inline]
            fn instruction_flags(&self) -> $crate::InstructionFlagSet {
                $crate::InstructionFlagSet::default()
                    $(.set($crate::InstructionFlags::$instruction))*
            }
        }

        $crate::jolt_instruction!(@jolt_instruction_impl $name);
    };

    (
        $(#[$attr:meta])*
        $name:ident $(,)?
    ) => {
        $crate::jolt_instruction!(@struct $(#[$attr])* $name);

        impl<T: $crate::JoltInstructionRowData> $crate::Flags for $name<T> {
            #[inline]
            fn circuit_flags(&self) -> $crate::CircuitFlagSet {
                let instruction: $crate::JoltInstructionRow = self.0.into();
                let mut flags = $crate::CircuitFlagSet::default();
                if let Some(virtual_sequence_remaining) = instruction.virtual_sequence_remaining {
                    flags = flags.set($crate::CircuitFlags::VirtualInstruction);
                    if virtual_sequence_remaining == 0 {
                        flags = flags.set($crate::CircuitFlags::IsLastInSequence);
                    }
                }
                if instruction.virtual_sequence_remaining.unwrap_or(0) != 0 {
                    flags = flags.set($crate::CircuitFlags::DoNotUpdateUnexpandedPC);
                }
                if instruction.is_compressed {
                    flags = flags.set($crate::CircuitFlags::IsCompressed);
                }
                if instruction.is_first_in_sequence {
                    flags = flags.set($crate::CircuitFlags::IsFirstInSequence);
                }
                flags
            }

            #[inline]
            fn instruction_flags(&self) -> $crate::InstructionFlagSet {
                $crate::InstructionFlagSet::default()
            }
        }

        $crate::jolt_instruction!(@jolt_instruction_impl $name);
    };

    // Internal: emit the struct definition.
    (@struct $(#[$attr:meta])* $name:ident) => {
        $(#[$attr])*
        #[derive(
            Clone,
            Copy,
            Debug,
            Default,
            PartialEq,
            Eq,
            Hash,
        )]
        #[cfg_attr(
            feature = "serialization",
            derive(::serde::Serialize, ::serde::Deserialize)
        )]
        pub struct $name<T = ()>(pub T);
    };

    // Internal: make the wrapper newtype participate in Jolt instruction-row
    // conversion marker by delegating through its payload.
    (@jolt_instruction_impl $name:ident) => {
        impl<T: $crate::JoltInstructionRowData> From<$name<T>> for $crate::JoltInstructionRow {
            #[inline]
            fn from(instruction: $name<T>) -> Self {
                instruction.0.into()
            }
        }

        impl<T: $crate::JoltInstructionRowData> TryFrom<$crate::JoltInstructionRow> for $name<T> {
            type Error = <T as TryFrom<$crate::JoltInstructionRow>>::Error;

            #[inline]
            fn try_from(instruction: $crate::JoltInstructionRow) -> Result<Self, Self::Error> {
                T::try_from(instruction).map($name)
            }
        }

        impl<T: $crate::JoltInstructionRowData> $crate::JoltInstructionRowData for $name<T> {
        }
    };
}
